     9→import rehypeSlug from 'rehype-slug';
    10→import rehypeImageMetadata from '@/lib/rehype-image-metadata';
    11→import { siteConfig } from '../../site.config';
    12→import remarkWikilinks from '@/lib/remark-wikilinks';
    13→import ExportedImage from 'next-image-export-optimizer';
    14→import { PluggableList } from 'unified';
    15→import type { SlugRegistryEntry } from '@/lib/markdown';
    16→
    17→interface MarkdownRendererProps {
    18→  content: string;
    19→  latex?: boolean;
    20→  slug?: string;
    21→  slugRegistry?: Map<string, SlugRegistryEntry>;
    22→}
    23→
    24→export default function MarkdownRenderer({ content, latex = false, slug, slugRegistry }: MarkdownRendererProps) {
    25→  const remarkPlugins: PluggableList = [remarkGfm];
    26→  const cdnBaseUrl = siteConfig.images?.cdnBaseUrl ?? '';
    27→  const rehypePlugins: PluggableList = [rehypeRaw, rehypeSlug, [rehypeImageMetadata, { slug, cdnBaseUrl }]];
    28→
    29→  if (slugRegistry && slugRegistry.size > 0) {
    30→    remarkPlugins.push([remarkWikilinks, { slugRegistry }]);
    31→  }
    32→
    33→  if (latex) {
    34→    remarkPlugins.push(remarkMath);
    35→    rehypePlugins.push(rehypeKatex);
    36→  }
    37→
    38→  const components: Components = {
    39→    // Use 'p' by default, but fallback to 'div' only if children contain block elements
    40→    // to avoid invalid HTML nesting warnings while preserving semantics.
    41→    p: ({ children }) => {
    42→      // Check if any child is a block-level element (like Mermaid or CodeBlock)
    43→      // Since children is a ReactNode, we can only do a shallow check here.
    44→      // Simple heuristic: if any child is not a string/number, it *might* be a block.
    45→      // However, react-markdown usually nests blocks at the top level.
    46→      return <p className="mb-4 leading-relaxed text-foreground">{children}</p>;
    47→    },
    48→    // Explicitly style lists to ensure contrast
    49→    li: ({ children }) => <li className="text-foreground">{children}</li>,
    50→    // Explicitly style blockquotes
    51→    blockquote: ({ children }) => <blockquote className="text-foreground border-l-accent italic">{children}</blockquote>,
    52→    // Explicitly style bold text
    53→    strong: ({ children }) => <strong className="text-heading font-semibold">{children}</strong>,
    54→    // Wrap tables in a scrollable container
    55→    table: (props) => {
    56→      // eslint-disable-next-line @typescript-eslint/no-unused-vars
    57→      const { children, node: _node, ...rest } = props as React.TableHTMLAttributes<HTMLTableElement> & ExtraProps;
    58→      return (
    59→        <div className="overflow-x-auto my-8 border border-muted/20 rounded-lg">
    60→          <table {...rest} className="min-w-full text-left text-sm">
    61→            {children}
    62→          </table>
    63→        </div>
    64→      );
    65→    },
    66→    // Render 'pre' as a 'div' to allow block-level children
    67→    pre: ({ children }) => <div className="not-prose">{children}</div>,
    68→    // Style links individually to avoid hover-all issue
    69→    a: (props) => {
    70→      // eslint-disable-next-line @typescript-eslint/no-unused-vars
    71→      const { node: _node, className, ...rest } = props as React.AnchorHTMLAttributes<HTMLAnchorElement> & ExtraProps;
    72→      // Preserve wikilink classes injected by remark-wikilinks — they have their own CSS styling
    73→      if (className?.includes('wikilink')) {
    74→        return <a {...rest} className={className} />;
    75→      }
    76→      return <a {...rest} className="text-accent no-underline hover:underline transition-colors duration-200" />;
    77→    },
    78→    // Custom code renderer: handles 'mermaid' blocks and syntax highlighting
    79→    code(props: React.ClassAttributes<HTMLElement> & React.HTMLAttributes<HTMLElement> & ExtraProps) {
    80→      // eslint-disable-next-line @typescript-eslint/no-unused-vars
    81→      const { className, children, node: _node, ...rest } = props;
    82→      const match = /language-(\w+)/.exec(className || '');
    83→      const language = match ? match[1] : '';
    84→      const isMultiLine = String(children).includes('\n');
