#!/usr/bin/env node

import * as fs from "fs";
import * as path from "path";
import * as https from "https";
import * as readline from "readline";
import { execSync } from "child_process";

// ---------------------------------------------------------------------------
// Helpers
// ---------------------------------------------------------------------------

function prompt(question: string, defaultVal: string = ""): Promise<string> {
  const rl = readline.createInterface({
    input: process.stdin,
    output: process.stdout,
  });
  const display = defaultVal ? `${question} (${defaultVal}): ` : `${question}: `;
  return new Promise((resolve) => {
    rl.question(display, (answer) => {
      rl.close();
      resolve(answer.trim() || defaultVal);
    });
  });
}

function fetchJson(url: string): Promise<Record<string, unknown>> {
  return new Promise((resolve, reject) => {
    https
      .get(url, { headers: { "User-Agent": "create-amytis-cli" } }, (res) => {
        if (res.statusCode === 301 || res.statusCode === 302) {
          fetchJson(res.headers.location!).then(resolve).catch(reject);
          return;
        }
        if (res.statusCode !== 200) {
          reject(new Error(`GitHub API returned ${res.statusCode} for ${url}`));
          return;
        }
        let data = "";
        res.on("data", (chunk) => (data += chunk));
        res.on("end", () => {
          try {
            resolve(JSON.parse(data) as Record<string, unknown>);
          } catch {
            reject(new Error("Failed to parse GitHub API response"));
          }
        });
      })
      .on("error", reject);
  });
}

function downloadFile(url: string, dest: string): Promise<void> {
  return new Promise((resolve, reject) => {
    const doGet = (targetUrl: string) => {
      https
        .get(targetUrl, { headers: { "User-Agent": "create-amytis-cli" } }, (res) => {
          if (res.statusCode === 301 || res.statusCode === 302) {
            doGet(res.headers.location!);
            return;
          }
          if (res.statusCode !== 200) {
            reject(new Error(`Download failed with status ${res.statusCode}`));
            return;
          }
          const file = fs.createWriteStream(dest);
          res.pipe(file);
          file.on("finish", () => file.close(() => resolve()));
          file.on("error", (err) => {
            fs.unlink(dest, () => {});
            reject(err);
          });
        })
        .on("error", reject);
    };
    doGet(url);
  });
}

function extractTarball(tarPath: string, outDir: string, stripPrefix: string): void {
  // Extract into a temp dir, then move the inner folder out
  const tmpDir = `${outDir}.__tmp__`;
  fs.mkdirSync(tmpDir, { recursive: true });
  execSync(`tar xzf "${tarPath}" -C "${tmpDir}"`);

  // The tarball unpacks to a single top-level dir like "amytis-1.2.0/"
  const entries = fs.readdirSync(tmpDir);
  if (entries.length !== 1) {
    throw new Error(`Unexpected tarball structure: ${entries.join(", ")}`);
  }
  const innerDir = path.join(tmpDir, entries[0]);
  fs.renameSync(innerDir, outDir);
  fs.rmdirSync(tmpDir);
  fs.unlinkSync(tarPath);
}

// ---------------------------------------------------------------------------
// Patch helpers
// ---------------------------------------------------------------------------

export function patchSiteConfig(projectDir: string, title: string, description: string): void {
  const configPath = path.join(projectDir, "site.config.ts");
  if (!fs.existsSync(configPath)) {
    console.warn("  Warning: site.config.ts not found, skipping patch");
    return;
  }

  let src = fs.readFileSync(configPath, "utf8");

  // title: { en: "...", zh: "..." }
  src = src.replace(
    /title:\s*\{\s*en:\s*"[^"]*",\s*zh:\s*"[^"]*"\s*\}/,
    `title: { en: ${JSON.stringify(title)}, zh: ${JSON.stringify(title)} }`
  );

  // description: { en: "...", zh: "..." }
  src = src.replace(
    /description:\s*\{\s*en:\s*"[^"]*",\s*zh:\s*"[^"]*"\s*\}/,
    `description: { en: ${JSON.stringify(description)}, zh: ${JSON.stringify(description)} }`
  );

  // footerText — replace "Amytis" occurrences in template literals with project title
  src = src.replace(
    /footerText:\s*\{\s*en:\s*`[^`]*`,\s*zh:\s*`[^`]*`\s*\}/,
    `footerText: { en: \`© \${new Date().getFullYear()} ${title}. All rights reserved.\`, zh: \`© \${new Date().getFullYear()} ${title}. 保留所有权利。\` }`
  );

  fs.writeFileSync(configPath, src, "utf8");
}

export function patchPackageJson(projectDir: string, projectName: string): void {
  const pkgPath = path.join(projectDir, "package.json");
  if (!fs.existsSync(pkgPath)) {
    console.warn("  Warning: package.json not found, skipping patch");
    return;
  }

  const pkg = JSON.parse(fs.readFileSync(pkgPath, "utf8")) as Record<string, unknown>;

  pkg["name"] = projectName;
  pkg["private"] = true;
  delete pkg["repository"];
  delete pkg["bugs"];
  delete pkg["homepage"];

  fs.writeFileSync(pkgPath, JSON.stringify(pkg, null, 2) + "\n", "utf8");
}

// ---------------------------------------------------------------------------
// Main
// ---------------------------------------------------------------------------

async function main(): Promise<void> {
  console.log("\nCreate Amytis — scaffold a new digital garden\n");

  // 1. Project name
  let projectName = process.argv[2] ?? "";
  if (!projectName) {
    projectName = await prompt("Project name", "my-blog");
  }

  const targetDir = path.resolve(process.cwd(), projectName);
  if (fs.existsSync(targetDir)) {
    console.error(`Error: directory "${projectName}" already exists.`);
    process.exit(1);
  }

  // 2. Fetch latest release tag
  console.log("\nFetching latest Amytis release...");
  const release = await fetchJson(
    "https://api.github.com/repos/hutusi/amytis/releases/latest"
  );
  const tag = release["tag_name"] as string;
  if (!tag) throw new Error("Could not determine latest release tag");
  console.log(`  Found: ${tag}`);

  // 3. Download tarball
  const tarUrl = `https://github.com/hutusi/amytis/archive/refs/tags/${tag}.tar.gz`;
  const tarDest = path.join(process.cwd(), `amytis-${tag}.tar.gz`);
  console.log("Downloading tarball...");
  await downloadFile(tarUrl, tarDest);

  // 4. Extract
  console.log("Extracting...");
  extractTarball(tarDest, targetDir, tag);
  console.log(`  Scaffolded: ${targetDir}`);

  // 5-6. Prompt for site metadata
  const siteTitle = await prompt("\nSite title", projectName);
  const siteDescription = await prompt(
    "Site description",
    "My digital garden"
  );

  // 7. Patch site.config.ts
  console.log("\nPatching site.config.ts...");
  patchSiteConfig(targetDir, siteTitle, siteDescription);

  // 8. Patch package.json
  console.log("Patching package.json...");
  patchPackageJson(targetDir, projectName);

  // 9. Run bun install
  console.log("Installing dependencies (bun install)...");
  execSync("bun install", { cwd: targetDir, stdio: "inherit" });

  // 10. Success message
  console.log(`
Done! Your new Amytis site is ready.

  cd ${projectName}
  bun dev          # start the dev server at http://localhost:3000
  bun run build    # production build

Edit site.config.ts to customise navigation, themes, and more.
Happy gardening!
`);
}

if (import.meta.main) {
  main().catch((err) => {
    console.error("\nError:", (err as Error).message);
    process.exit(1);
  });
}

import { getPostBySlug, getAllPosts, getRelatedPosts, getSeriesPosts, getSeriesData, getAdjacentPosts, buildSlugRegistry, getBacklinks, PostData } from '@/lib/markdown';
import { notFound } from 'next/navigation';
import PostLayout from '@/layouts/PostLayout';
import SimpleLayout from '@/layouts/SimpleLayout';
import { Metadata } from 'next';
import { siteConfig } from '../../../../site.config';
import { resolveLocale } from '@/lib/i18n';
import { getPostsBasePath, getSeriesCustomPaths } from '@/lib/urls';

function safeDecodeParam(param: string): string {
  try {
    return decodeURIComponent(param);
  } catch {
    return param;
  }
}

function resolvePostFromParam(rawSlug: string) {
  const decoded = safeDecodeParam(rawSlug);
  return (
    getPostBySlug(decoded) ||
    getPostBySlug(rawSlug) ||
    getPostBySlug(decoded.normalize('NFC')) ||
    getPostBySlug(decoded.normalize('NFD'))
  );
}

export async function generateStaticParams() {
  const params: { slug: string; postSlug: string }[] = [];

  // Custom posts basePath — all posts served at /[basePath]/[slug]
  const basePath = getPostsBasePath();
  if (basePath !== 'posts') {
    getAllPosts().forEach(post => { params.push({ slug: basePath, postSlug: post.slug }); });
  }

  // Series custom paths — only posts belonging to that series
  for (const [seriesSlug, customPath] of Object.entries(getSeriesCustomPaths())) {
    getSeriesPosts(seriesSlug).forEach(post => { params.push({ slug: customPath, postSlug: post.slug }); });
  }

  // Placeholder keeps Next.js happy with output: export when no custom paths configured.
  // dynamicParams = false ensures any unrecognised slug/postSlug combo returns 404.
  return params.length > 0 ? params : [{ slug: '_', postSlug: '_' }];
}

export const dynamicParams = false;

export async function generateMetadata({
  params,
}: {
  params: Promise<{ slug: string; postSlug: string }>;
}): Promise<Metadata> {
  const { postSlug: rawPostSlug } = await params;
  const post = resolvePostFromParam(rawPostSlug);

  if (!post) {
    return { title: 'Post Not Found' };
  }

  const ogImage =
    post.coverImage && !post.coverImage.startsWith('text:') && !post.coverImage.startsWith('./')
      ? post.coverImage
      : siteConfig.ogImage;

  return {
    title: `${post.title} | ${resolveLocale(siteConfig.title)}`,
    description: post.excerpt,
    openGraph: {
      title: post.title,
      description: post.excerpt,
      type: 'article',
      publishedTime: post.date,
      authors: post.authors,
      images: [
        {
          url: ogImage,
          width: 1200,
          height: 630,
          alt: post.title,
        },
      ],
      siteName: resolveLocale(siteConfig.title),
    },
    twitter: {
      card: 'summary_large_image',
      title: post.title,
      description: post.excerpt,
      images: [ogImage],
    },
  };
}

export default async function PrefixPostPage({
  params,
}: {
  params: Promise<{ slug: string; postSlug: string }>;
}) {
  const { slug: prefix, postSlug: rawPostSlug } = await params;
  const postSlug = safeDecodeParam(rawPostSlug);

  // Validate the prefix is a known custom path
  const basePath = getPostsBasePath();
  const customPaths = getSeriesCustomPaths();
  const isValidBasePath = prefix === basePath && basePath !== 'posts';
  const matchedSeriesSlug = Object.entries(customPaths).find(([, path]) => path === prefix)?.[0];

  if (!isValidBasePath && !matchedSeriesSlug) {
    notFound();
  }

  const post = resolvePostFromParam(rawPostSlug);
  if (!post) {
    notFound();
  }

  const layout = post.layout || 'post';

  if (layout === 'simple') {
    return <SimpleLayout post={post} />;
  }

  const relatedPosts = getRelatedPosts(post.slug);
  const { prev, next } = getAdjacentPosts(post.slug);
  const slugRegistry = buildSlugRegistry();
  const backlinks = getBacklinks(post.slug);
  let seriesPosts: PostData[] = [];
  let seriesTitle: string | undefined;

  if (post.series) {
    seriesPosts = getSeriesPosts(post.series);
    const seriesData = getSeriesData(post.series);
    seriesTitle = seriesData?.title;
  }

  return (
    <PostLayout
      post={post}
      relatedPosts={relatedPosts}
      seriesPosts={seriesPosts}
      seriesTitle={seriesTitle}
      prevPost={prev}
      nextPost={next}
      backlinks={backlinks}
      slugRegistry={slugRegistry}
    />
  );
}

import { getPageBySlug, getAllPages, getAllPosts, getListingPosts, getSeriesData, getSeriesPosts, getSeriesAuthors, getAuthorSlug } from '@/lib/markdown';
import { notFound } from 'next/navigation';
import PostLayout from '@/layouts/PostLayout';
import SimpleLayout from '@/layouts/SimpleLayout';
import PostList from '@/components/PostList';
import SeriesCatalog from '@/components/SeriesCatalog';
import Pagination from '@/components/Pagination';
import CoverImage from '@/components/CoverImage';
import Link from 'next/link';
import { Metadata } from 'next';
import { siteConfig } from '../../../site.config';
import { resolveLocale, t } from '@/lib/i18n';
import PageHeader from '@/components/PageHeader';
import { getPostsBasePath, getSeriesCustomPaths } from '@/lib/urls';

const POST_PAGE_SIZE = siteConfig.pagination.posts;
const SERIES_PAGE_SIZE = siteConfig.pagination.series;

/**
 * Generates the static paths for all top-level pages at build time,
 * plus any custom URL prefixes configured for posts or series.
 */
export async function generateStaticParams() {
  const pages = getAllPages();
  const params = pages.map((page) => ({ slug: page.slug }));

  // Add custom posts basePath listing (e.g. /articles)
  const basePath = getPostsBasePath();
  if (basePath !== 'posts') {
    params.push({ slug: basePath });
  }

  // Add series custom path listings (e.g. /weeklies)
  for (const customPath of Object.values(getSeriesCustomPaths())) {
    params.push({ slug: customPath });
  }

  return params;
}

export const dynamicParams = false;

export async function generateMetadata({ params }: { params: Promise<{ slug: string }> }): Promise<Metadata> {
  const { slug: rawSlug } = await params;
  const slug = decodeURIComponent(rawSlug);

  // Custom posts basePath
  const basePath = getPostsBasePath();
  if (slug === basePath && basePath !== 'posts') {
    return {
      title: `${t('posts')} | ${resolveLocale(siteConfig.title)}`,
      description: 'Browse the complete archive of articles.',
    };
  }

  // Series custom paths
  const customPaths = getSeriesCustomPaths();
  const matchedSeriesSlug = Object.entries(customPaths).find(([, path]) => path === slug)?.[0];
  if (matchedSeriesSlug) {
    const seriesData = getSeriesData(matchedSeriesSlug);
    if (seriesData) {
      return {
        title: `${seriesData.title} - ${t('series')} | ${resolveLocale(siteConfig.title)}`,
        description: seriesData.excerpt,
      };
    }
  }

  const page = getPageBySlug(slug);
  if (!page) {
    return { title: 'Page Not Found' };
  }

  return {
    title: `${page.title} | ${resolveLocale(siteConfig.title)}`,
    description: page.excerpt,
  };
}

export default async function Page({
  params,
}: {
  params: Promise<{ slug: string }>;
}) {
  const { slug: rawSlug } = await params;
  const slug = decodeURIComponent(rawSlug);

  // Check if slug matches custom posts basePath
  const basePath = getPostsBasePath();
  if (slug === basePath && basePath !== 'posts') {
    const allPosts = getListingPosts();
    const totalPages = Math.ceil(allPosts.length / POST_PAGE_SIZE);
    const posts = allPosts.slice(0, POST_PAGE_SIZE);

    return (
      <div className="layout-main">
        <PageHeader
          titleKey="posts"
          subtitleKey="posts_subtitle"
          subtitleParams={{ count: allPosts.length }}
          className="mb-12"
        />
        <PostList posts={posts} />
        {totalPages > 1 && (
          <div className="mt-12">
            <Pagination currentPage={1} totalPages={totalPages} basePath={`/${basePath}`} />
          </div>
        )}
      </div>
    );
  }

  // Check if slug matches a series custom path
  const customPaths = getSeriesCustomPaths();
  const matchedSeriesSlug = Object.entries(customPaths).find(([, path]) => path === slug)?.[0];
  if (matchedSeriesSlug) {
    const seriesData = getSeriesData(matchedSeriesSlug);
    const allPosts = getSeriesPosts(matchedSeriesSlug);

    if ((!seriesData && allPosts.length === 0) || (process.env.NODE_ENV === 'production' && seriesData?.draft)) {
      notFound();
    }

    const totalPages = Math.ceil(allPosts.length / SERIES_PAGE_SIZE);
    const posts = allPosts.slice(0, SERIES_PAGE_SIZE);

    const title = seriesData?.title || matchedSeriesSlug.charAt(0).toUpperCase() + matchedSeriesSlug.slice(1);
    const description = seriesData?.excerpt;
    const coverImage = seriesData?.coverImage;

    const explicitAuthors = getSeriesAuthors(matchedSeriesSlug);
    let authors: string[];
    if (explicitAuthors) {
      authors = explicitAuthors;
    } else if (allPosts.length > 0) {
      const counts = new Map<string, number>();
      for (const post of allPosts) {
        for (const author of post.authors) {
          counts.set(author, (counts.get(author) || 0) + 1);
        }
      }
      authors = [...counts.entries()].sort((a, b) => b[1] - a[1]).map(([name]) => name);
    } else {
      authors = [];
    }

    return (
      <div className="layout-main">
        <header className="mb-16">
          {coverImage && (
            <div className="relative w-full h-56 md:h-72 mb-10 rounded-2xl overflow-hidden shadow-xl shadow-accent/5">
              <CoverImage
                src={coverImage}
                title={title}
                slug={matchedSeriesSlug}
                className="w-full h-full object-cover"
              />
              <div className="absolute inset-0 bg-gradient-to-t from-background/60 to-transparent" />
            </div>
          )}
          <div className="text-center max-w-2xl mx-auto">
            <span className="badge-accent mb-4">
              {t('series')} • {allPosts.length} {t('parts')}
            </span>
            <h1 className="page-title mb-4">{title}</h1>
            {description && (
              <p className="text-lg text-muted font-serif italic leading-relaxed">{description}</p>
            )}
            {authors.length > 0 && (
              <p className="mt-4 text-sm text-muted">
                <span className="mr-1">{t('written_by')}</span>
                {authors.map((author, index) => (
                  <span key={author}>
                    <Link
                      href={`/authors/${getAuthorSlug(author)}`}
                      className="text-foreground hover:text-accent no-underline transition-colors duration-200"
                    >
                      {author}
                    </Link>
                    {index < authors.length - 1 && <span className="mr-1">,</span>}
                  </span>
                ))}
              </p>
            )}
          </div>
        </header>
        <SeriesCatalog posts={posts} totalPosts={allPosts.length} />
        {totalPages > 1 && (
          <div className="mt-12">
            <Pagination currentPage={1} totalPages={totalPages} basePath={`/${slug}`} />
          </div>
        )}
      </div>
    );
  }

  // Default: static page
  const page = getPageBySlug(slug);

  if (!page) {
    notFound();
  }

  // Determine layout based on frontmatter, defaulting to 'simple' for pages
  const layout = page.layout || 'simple';

  if (layout === 'post') {
    return <PostLayout post={page} />;
  }

  return <SimpleLayout post={page} />;
}

